--
-- TOC entry 221 (class 1259 OID 16540)
-- Name: v_domain_stats; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_domain_stats AS
 SELECT domain,
    count(*) AS total_dokumen,
    count(*) FILTER (WHERE ((status)::text = 'aktif'::text)) AS aktif,
    count(*) FILTER (WHERE ((status)::text = 'arsip'::text)) AS arsip,
    count(*) FILTER (WHERE ((status)::text = 'draft'::text)) AS draft
   FROM public.documents
  GROUP BY domain
  ORDER BY domain;


ALTER VIEW public.v_domain_stats OWNER TO postgres;

--
-- TOC entry 220 (class 1259 OID 16536)
-- Name: v_pending_review; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_pending_review AS
 SELECT id,
    file_name,
    detected_domain,
    file_type,
    (extracted_metadata ->> 'judul'::text) AS judul,
    (extracted_metadata ->> 'ringkasan'::text) AS ringkasan,
    (extracted_metadata ->> 'doc_type'::text) AS doc_type,
    created_at
   FROM public.staging_queue sq
  WHERE ((status)::text = 'pending'::text)
  ORDER BY created_at;


ALTER VIEW public.v_pending_review OWNER TO postgres;

